// // This module is designed to decrement a 3-bit counter on each positive clock edge and wrap around at 0.
module top_module(
    input clk,
    input rst,
    output reg [2:0] count
);always @(posedge clk, posedge rst) begin
    if (rst) begin
        count <= 3'b0;
    end else begin
        count <= count + 1;
    end
end

endmodule
